array.forEach((element, index, array) => {
  // side effect here
});

// Only the element is required; index and array are optional:
['a', 'b', 'c'].forEach(letter => {
  console.log(letter);
});
// 'a'
// 'b'
// 'c'

const fruits = ['apple', 'banana', 'cherry'];

// Log each element:
fruits.forEach(fruit => console.log(fruit));
// 'apple', 'banana', 'cherry'

// Log element and index:
fruits.forEach((fruit, index) => {
  console.log(`${index}: ${fruit}`);
});
// '0: apple'
// '1: banana'
// '2: cherry'

// Push to an external array (classic side effect):
const lengths = [];
fruits.forEach(fruit => lengths.push(fruit.length));
console.log(lengths); // [5, 6, 6]

const numbers = [1, 2, 3];

// ✅ forEach — for side effects:
numbers.forEach(n => console.log(n * 2)); // logs 2, 4, 6

// ✅ map — to get a new array:
const doubled = numbers.map(n => n * 2); // [2, 4, 6]

// ❌ forEach doesn't produce a value:
const result = numbers.forEach(n => n * 2);
console.log(result); // undefined

const numbers = [1, 2, 3, 4, 5];

// 'return' inside forEach only skips to the next iteration:
numbers.forEach(n => {
  if (n === 3) return; // this is NOT a break — continues to 4, 5
  console.log(n);
});
// 1, 2, 4, 5

// ✅ If you need to stop early, use a for...of loop:
for (const n of numbers) {
  if (n === 3) break; // stops the loop
  console.log(n);
}
// 1, 2

const users = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' },
];

users.forEach(user => console.log(user.name)); // Alice, Bob

// Build a Map from an array:
const usersById = new Map();
users.forEach(user => usersById.set(user.id, user));
console.log(usersById.get(1)); // { id: 1, name: 'Alice' }

// Accumulate totals:
const prices = [10, 25, 8, 42];
let total = 0;
prices.forEach(price => (total += price));
console.log(total); // 85

// Send analytics events for each item
const items = ['home', 'about', 'contact'];
items.forEach(page => analytics.track('pageview', { page }));

// Register event listeners
const buttons = document.querySelectorAll('button');
buttons.forEach(btn => btn.addEventListener('click', handleClick));

const nums = [1, 2, 3];

// The array itself is NOT changed by the forEach call:
nums.forEach(n => n * 2);
console.log(nums); // [1, 2, 3] — unchanged

// But a callback can mutate objects by reference:
const users = [{ name: 'alice' }, { name: 'bob' }];
users.forEach(user => {
  user.name = user.name.toUpperCase(); // mutates the object
});
console.log(users); // [{ name: 'ALICE' }, { name: 'BOB' }]

import { useEffect } from 'react';

function App({ notifications }) {
  useEffect(() => {
    // Mark all notifications as seen (side effect — no new array needed)
    notifications.forEach(notification => {
      markAsSeen(notification.id);
    });
  }, [notifications]);

  // Render with map, not forEach:
  return (
    <ul>
      {notifications.map(n => (
        <li key={n.id}>{n.message}</li>
      ))}
    </ul>
  );
}

function handleSubmit(e) {
  e.preventDefault();

  const errors = [];
  const fields = ['name', 'email', 'password'];

  fields.forEach(field => {
    if (!formData[field]) {
      errors.push(`${field} is required`);
    }
  });

  if (errors.length > 0) {
    setErrors(errors);
    return;
  }

  submitForm(formData);
}
